window.BIBLE["Galatians"] = {"1":{"chapter":"1","title":"BUT THOUGH WE OR AN ANGEL — PREACH ANOTHER GOSPEL","verses":{"1":{"text":"Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead;)","ref":"Galatians 1:1","synthesized":"Paul, an apostle—sent not from men nor by man, but by Jesus Christ and God the Father, who raised Him from the dead—","sources":{"KJV":{"text":"Paul, an apostle, (not of men, neither by man, but by Jesus Christ, and God the Father, who raised him from the dead;)"},"BSB":{"text":"Paul, an apostle—sent not from men nor by man, but by Jesus Christ and God the Father, who raised Him from the dead—"}},"definableWords":["apostle","men","man","Christ","God","Father"],"peopleInVerse":["Paul","Jesus"]},"2":{"text":"And all the brethren which are with me, unto the churches of Galatia:","ref":"Galatians 1:2","synthesized":"and all the brothers with me,  To the churches of Galatia:","sources":{"KJV":{"text":"And all the brethren which are with me, unto the churches of Galatia:"},"BSB":{"text":"and all the brothers with me,  To the churches of Galatia:"}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"Grace be to you and peace from God the Father, and from our Lord Jesus Christ,","ref":"Galatians 1:3","synthesized":"Grace and peace to you from God our Father and the Lord Jesus Christ,","sources":{"KJV":{"text":"Grace be to you and peace from God the Father, and from our Lord Jesus Christ,"},"BSB":{"text":"Grace and peace to you from God our Father and the Lord Jesus Christ,"}},"definableWords":["grace","peace","God","Father","Lord","Christ"],"peopleInVerse":["Jesus"]},"4":{"text":"Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father:","ref":"Galatians 1:4","synthesized":"who gave Himself for our sins to rescue us from the present evil age, according to the will of our God and Father,","sources":{"KJV":{"text":"Who gave himself for our sins, that he might deliver us from this present evil world, according to the will of God and our Father:"},"BSB":{"text":"who gave Himself for our sins to rescue us from the present evil age, according to the will of our God and Father,"}},"definableWords":["evil","God","Father"],"peopleInVerse":[]},"5":{"text":"To whom be glory for ever and ever. Amen.","ref":"Galatians 1:5","synthesized":"to whom be glory forever and ever. Amen.","sources":{"KJV":{"text":"To whom be glory for ever and ever. Amen."},"BSB":{"text":"to whom be glory forever and ever. Amen."}},"definableWords":["glory"],"peopleInVerse":[]},"6":{"text":"I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel:","ref":"Galatians 1:6","synthesized":"I am amazed how quickly you are deserting the One who called you by the grace of Christ and are turning to a different gospel—","sources":{"KJV":{"text":"I marvel that ye are so soon removed from him that called you into the grace of Christ unto another gospel:"},"BSB":{"text":"I am amazed how quickly you are deserting the One who called you by the grace of Christ and are turning to a different gospel—"}},"definableWords":["one","grace","Christ","gospel"],"peopleInVerse":[]},"7":{"text":"Which is not another; but there be some that trouble you, and would pervert the gospel of Christ.","ref":"Galatians 1:7","synthesized":"which is not even a gospel. Evidently some people are troubling you and trying to distort the gospel of Christ.","sources":{"KJV":{"text":"Which is not another; but there be some that trouble you, and would pervert the gospel of Christ."},"BSB":{"text":"which is not even a gospel. Evidently some people are troubling you and trying to distort the gospel of Christ."}},"definableWords":["gospel","people","Christ"],"peopleInVerse":[]},"8":{"text":"But though we, or an angel from heaven, preach any other gospel unto you than that which we have preached unto you, let him be accursed.","ref":"Galatians 1:8","synthesized":"But even if we or an angel from heaven should preach a gospel contrary to the one we preached to you, let him be under a curse!","sources":{"KJV":{"text":"But though we, or an angel from heaven, preach any other gospel unto you than that which we have preached unto you, let him be accursed."},"BSB":{"text":"But even if we or an angel from heaven should preach a gospel contrary to the one we preached to you, let him be under a curse!"}},"definableWords":["or","angel","heaven","gospel","one","curse"],"peopleInVerse":[]},"9":{"text":"As we said before, so say I now again, If any man preach any other gospel unto you than that ye have received, let him be accursed.","ref":"Galatians 1:9","synthesized":"As we have said before, so now I say again: If anyone is preaching to you a gospel contrary to the one you received, let him be under a curse!","sources":{"KJV":{"text":"As we said before, so say I now again, If any man preach any other gospel unto you than that ye have received, let him be accursed."},"BSB":{"text":"As we have said before, so now I say again: If anyone is preaching to you a gospel contrary to the one you received, let him be under a curse!"}},"definableWords":["gospel","one","curse"],"peopleInVerse":[]},"10":{"text":"For do I now persuade men, or God? or do I seek to please men? for if I yet pleased men, I should not be the servant of Christ.","ref":"Galatians 1:10","synthesized":"Am I now seeking the approval of men, or of God? Or am I striving to please men? If I were still trying to please men, I would not be a servant of Christ.","sources":{"KJV":{"text":"For do I now persuade men, or God? or do I seek to please men? for if I yet pleased men, I should not be the servant of Christ."},"BSB":{"text":"Am I now seeking the approval of men, or of God? Or am I striving to please men? If I were still trying to please men, I would not be a servant of Christ."}},"definableWords":["men","or","God","servant","Christ"],"peopleInVerse":[]},"11":{"text":"But I certify you, brethren, that the gospel which was preached of me is not after man.","ref":"Galatians 1:11","synthesized":"For I certify to you, brothers, that the gospel I preached was not devised by man.","sources":{"KJV":{"text":"But I certify you, brethren, that the gospel which was preached of me is not after man."},"BSB":{"text":"For I certify to you, brothers, that the gospel I preached was not devised by man."}},"definableWords":["gospel","man"],"peopleInVerse":[]},"12":{"text":"For I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ.","ref":"Galatians 1:12","synthesized":"I did not receive it from any man, nor was I taught it; rather, I received it by revelation from Jesus Christ.","sources":{"KJV":{"text":"For I neither received it of man, neither was I taught it, but by the revelation of Jesus Christ."},"BSB":{"text":"I did not receive it from any man, nor was I taught it; rather, I received it by revelation from Jesus Christ."}},"definableWords":["man","Christ"],"peopleInVerse":["Jesus"]},"13":{"text":"For ye have heard of my conversation in time past in the Jews’ religion, how that beyond measure I persecuted the church of God, and wasted it:","ref":"Galatians 1:13","synthesized":"For you have heard of my former way of life in Judaism, how severely I persecuted the church of God and tried to destroy it.","sources":{"KJV":{"text":"For ye have heard of my conversation in time past in the Jews’ religion, how that beyond measure I persecuted the church of God, and wasted it:"},"BSB":{"text":"For you have heard of my former way of life in Judaism, how severely I persecuted the church of God and tried to destroy it."}},"definableWords":["way","life","church","God"],"peopleInVerse":[]},"14":{"text":"And profited in the Jews’ religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers.","ref":"Galatians 1:14","synthesized":"I was advancing in Judaism beyond many of my contemporaries and was extremely zealous for the traditions of my fathers.","sources":{"KJV":{"text":"And profited in the Jews’ religion above many my equals in mine own nation, being more exceedingly zealous of the traditions of my fathers."},"BSB":{"text":"I was advancing in Judaism beyond many of my contemporaries and was extremely zealous for the traditions of my fathers."}},"definableWords":["fathers"],"peopleInVerse":[]},"15":{"text":"But when it pleased God, who separated me from my mother’s womb, and called me by his grace,","ref":"Galatians 1:15","synthesized":"But when God, who set me apart from my mother’s womb and called me by His grace, was pleased","sources":{"KJV":{"text":"But when it pleased God, who separated me from my mother’s womb, and called me by his grace,"},"BSB":{"text":"But when God, who set me apart from my mother’s womb and called me by His grace, was pleased"}},"definableWords":["God","mother","grace"],"peopleInVerse":[]},"16":{"text":"To reveal his Son in me, that I might preach him among the heathen; immediately I conferred not with flesh and blood:","ref":"Galatians 1:16","synthesized":"to reveal His Son in me so that I might preach Him among the Gentiles, I did not rush to consult with flesh and blood,","sources":{"KJV":{"text":"To reveal his Son in me, that I might preach him among the heathen; immediately I conferred not with flesh and blood:"},"BSB":{"text":"to reveal His Son in me so that I might preach Him among the Gentiles, I did not rush to consult with flesh and blood,"}},"definableWords":["Son","flesh","blood"],"peopleInVerse":[]},"17":{"text":"Neither went I up to Jerusalem to them which were apostles before me; but I went into Arabia, and returned again unto Damascus.","ref":"Galatians 1:17","synthesized":"nor did I go up to Jerusalem to the apostles who came before me, but I went into Arabia and later returned to Damascus.","sources":{"KJV":{"text":"Neither went I up to Jerusalem to them which were apostles before me; but I went into Arabia, and returned again unto Damascus."},"BSB":{"text":"nor did I go up to Jerusalem to the apostles who came before me, but I went into Arabia and later returned to Damascus."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"18":{"text":"Then after three years I went up to Jerusalem to see Peter, and abode with him fifteen days.","ref":"Galatians 1:18","synthesized":"Only after three years did I go up to Jerusalem to confer with Cephas, and I stayed with him fifteen days.","sources":{"KJV":{"text":"Then after three years I went up to Jerusalem to see Peter, and abode with him fifteen days."},"BSB":{"text":"Only after three years did I go up to Jerusalem to confer with Cephas, and I stayed with him fifteen days."}},"definableWords":["years","Jerusalem","days"],"peopleInVerse":[]},"19":{"text":"But other of the apostles saw I none, save James the Lord’s brother.","ref":"Galatians 1:19","synthesized":"But I saw none of the other apostles except James, the Lord’s brother.","sources":{"KJV":{"text":"But other of the apostles saw I none, save James the Lord’s brother."},"BSB":{"text":"But I saw none of the other apostles except James, the Lord’s brother."}},"definableWords":["saw","Lord","brother"],"peopleInVerse":["James"]},"20":{"text":"Now the things which I write unto you, behold, before God, I lie not.","ref":"Galatians 1:20","synthesized":"I assure you before God that what I am writing to you is no lie.","sources":{"KJV":{"text":"Now the things which I write unto you, behold, before God, I lie not."},"BSB":{"text":"I assure you before God that what I am writing to you is no lie."}},"definableWords":["God"],"peopleInVerse":[]},"21":{"text":"Afterwards I came into the regions of Syria and Cilicia;","ref":"Galatians 1:21","synthesized":"Later I went to the regions of Syria and Cilicia.","sources":{"KJV":{"text":"Afterwards I came into the regions of Syria and Cilicia;"},"BSB":{"text":"Later I went to the regions of Syria and Cilicia."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"And was unknown by face unto the churches of Judaea which were in Christ:","ref":"Galatians 1:22","synthesized":"I was personally unknown, however, to the churches of Judea that are in Christ.","sources":{"KJV":{"text":"And was unknown by face unto the churches of Judaea which were in Christ:"},"BSB":{"text":"I was personally unknown, however, to the churches of Judea that are in Christ."}},"definableWords":["Judea","Christ"],"peopleInVerse":[]},"23":{"text":"But they had heard only, That he which persecuted us in times past now preacheth the faith which once he destroyed.","ref":"Galatians 1:23","synthesized":"They only heard the account: “The man who formerly persecuted us is now preaching the faith he once tried to destroy.”","sources":{"KJV":{"text":"But they had heard only, That he which persecuted us in times past now preacheth the faith which once he destroyed."},"BSB":{"text":"They only heard the account: “The man who formerly persecuted us is now preaching the faith he once tried to destroy.”"}},"definableWords":["man","faith"],"peopleInVerse":[]},"24":{"text":"And they glorified God in me.","ref":"Galatians 1:24","synthesized":"And they glorified God because of me.","sources":{"KJV":{"text":"And they glorified God in me."},"BSB":{"text":"And they glorified God because of me."}},"definableWords":["God"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"I AM CRUCIFIED WITH CHRIST","verses":{"1":{"text":"Then fourteen years after I went up again to Jerusalem with Barnabas, and took Titus with me also.","ref":"Galatians 2:1","synthesized":"Fourteen years later I went up again to Jerusalem, accompanied by Barnabas. I took Titus along also.","sources":{"KJV":{"text":"Then fourteen years after I went up again to Jerusalem with Barnabas, and took Titus with me also."},"BSB":{"text":"Fourteen years later I went up again to Jerusalem, accompanied by Barnabas. I took Titus along also."}},"definableWords":["years","Jerusalem"],"peopleInVerse":["Barnabas"]},"2":{"text":"And I went up by revelation, and communicated unto them that gospel which I preach among the Gentiles, but privately to them which were of reputation, lest by any means I should run, or had run, in vain.","ref":"Galatians 2:2","synthesized":"I went in response to a revelation and set before them the gospel that I preach among the Gentiles. But I spoke privately to those recognized as leaders, for fear that I was running or had already run in vain.","sources":{"KJV":{"text":"And I went up by revelation, and communicated unto them that gospel which I preach among the Gentiles, but privately to them which were of reputation, lest by any means I should run, or had run, in vain."},"BSB":{"text":"I went in response to a revelation and set before them the gospel that I preach among the Gentiles. But I spoke privately to those recognized as leaders, for fear that I was running or had already run in vain."}},"definableWords":["gospel","fear","or","run"],"peopleInVerse":[]},"3":{"text":"But neither Titus, who was with me, being a Greek, was compelled to be circumcised:","ref":"Galatians 2:3","synthesized":"Yet not even Titus, who was with me, was compelled to be circumcised, even though he was a Greek.","sources":{"KJV":{"text":"But neither Titus, who was with me, being a Greek, was compelled to be circumcised:"},"BSB":{"text":"Yet not even Titus, who was with me, was compelled to be circumcised, even though he was a Greek."}},"definableWords":["circumcised","Greek"],"peopleInVerse":[]},"4":{"text":"And that because of false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage:","ref":"Galatians 2:4","synthesized":"This issue arose because some false brothers had come in under false pretenses to spy on our freedom in Christ Jesus, in order to enslave us.","sources":{"KJV":{"text":"And that because of false brethren unawares brought in, who came in privily to spy out our liberty which we have in Christ Jesus, that they might bring us into bondage:"},"BSB":{"text":"This issue arose because some false brothers had come in under false pretenses to spy on our freedom in Christ Jesus, in order to enslave us."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"5":{"text":"To whom we gave place by subjection, no, not for an hour; that the truth of the gospel might continue with you.","ref":"Galatians 2:5","synthesized":"We did not give in to them for a moment, so that the truth of the gospel would remain with you.","sources":{"KJV":{"text":"To whom we gave place by subjection, no, not for an hour; that the truth of the gospel might continue with you."},"BSB":{"text":"We did not give in to them for a moment, so that the truth of the gospel would remain with you."}},"definableWords":["truth","gospel"],"peopleInVerse":[]},"6":{"text":"But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man’s person:) for they who seemed to be somewhat in conference added nothing to me:","ref":"Galatians 2:6","synthesized":"But as for the highly esteemed—whatever they were makes no difference to me; God does not show favoritism—those leaders added nothing to me.","sources":{"KJV":{"text":"But of these who seemed to be somewhat, (whatsoever they were, it maketh no matter to me: God accepteth no man’s person:) for they who seemed to be somewhat in conference added nothing to me:"},"BSB":{"text":"But as for the highly esteemed—whatever they were makes no difference to me; God does not show favoritism—those leaders added nothing to me."}},"definableWords":["God"],"peopleInVerse":[]},"7":{"text":"But contrariwise, when they saw that the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter;","ref":"Galatians 2:7","synthesized":"On the contrary, they saw that I had been entrusted to preach the gospel to the uncircumcised, just as Peter had been to the circumcised.","sources":{"KJV":{"text":"But contrariwise, when they saw that the gospel of the uncircumcision was committed unto me, as the gospel of the circumcision was unto Peter;"},"BSB":{"text":"On the contrary, they saw that I had been entrusted to preach the gospel to the uncircumcised, just as Peter had been to the circumcised."}},"definableWords":["saw","gospel","circumcised"],"peopleInVerse":["Peter"]},"8":{"text":"(For he that wrought effectually in Peter to the apostleship of the circumcision, the same was mighty in me toward the Gentiles:)","ref":"Galatians 2:8","synthesized":"For the One who was at work in Peter’s apostleship to the circumcised was also at work in my apostleship to the Gentiles.","sources":{"KJV":{"text":"(For he that wrought effectually in Peter to the apostleship of the circumcision, the same was mighty in me toward the Gentiles:)"},"BSB":{"text":"For the One who was at work in Peter’s apostleship to the circumcised was also at work in my apostleship to the Gentiles."}},"definableWords":["one","work","circumcised"],"peopleInVerse":["Peter"]},"9":{"text":"And when James, Cephas, and John, who seemed to be pillars, perceived the grace that was given unto me, they gave to me and Barnabas the right hands of fellowship; that we should go unto the heathen, and they unto the circumcision.","ref":"Galatians 2:9","synthesized":"And recognizing the grace that I had been given, James, Cephas, and John—those reputed to be pillars—gave me and Barnabas the right hand of fellowship, so that we should go to the Gentiles, and they to the circumcised.","sources":{"KJV":{"text":"And when James, Cephas, and John, who seemed to be pillars, perceived the grace that was given unto me, they gave to me and Barnabas the right hands of fellowship; that we should go unto the heathen, and they unto the circumcision."},"BSB":{"text":"And recognizing the grace that I had been given, James, Cephas, and John—those reputed to be pillars—gave me and Barnabas the right hand of fellowship, so that we should go to the Gentiles, and they to the circumcised."}},"definableWords":["grace","circumcised"],"peopleInVerse":["James","John","Barnabas"]},"10":{"text":"Only they would that we should remember the poor; the same which I also was forward to do.","ref":"Galatians 2:10","synthesized":"They only asked us to remember the poor, the very thing I was eager to do.","sources":{"KJV":{"text":"Only they would that we should remember the poor; the same which I also was forward to do."},"BSB":{"text":"They only asked us to remember the poor, the very thing I was eager to do."}},"definableWords":["remember"],"peopleInVerse":[]},"11":{"text":"But when Peter was come to Antioch, I withstood him to the face, because he was to be blamed.","ref":"Galatians 2:11","synthesized":"When Cephas came to Antioch, however, I opposed him to his face, because he stood to be condemned.","sources":{"KJV":{"text":"But when Peter was come to Antioch, I withstood him to the face, because he was to be blamed."},"BSB":{"text":"When Cephas came to Antioch, however, I opposed him to his face, because he stood to be condemned."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew and separated himself, fearing them which were of the circumcision.","ref":"Galatians 2:12","synthesized":"For before certain men came from James, he used to eat with the Gentiles. But when they arrived, he began to draw back and separate himself, for fear of those in the circumcision group.","sources":{"KJV":{"text":"For before that certain came from James, he did eat with the Gentiles: but when they were come, he withdrew and separated himself, fearing them which were of the circumcision."},"BSB":{"text":"For before certain men came from James, he used to eat with the Gentiles. But when they arrived, he began to draw back and separate himself, for fear of those in the circumcision group."}},"definableWords":["men","fear","circumcision"],"peopleInVerse":["James"]},"13":{"text":"And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation.","ref":"Galatians 2:13","synthesized":"The other Jews joined him in his hypocrisy, so that by their hypocrisy even Barnabas was led astray.","sources":{"KJV":{"text":"And the other Jews dissembled likewise with him; insomuch that Barnabas also was carried away with their dissimulation."},"BSB":{"text":"The other Jews joined him in his hypocrisy, so that by their hypocrisy even Barnabas was led astray."}},"definableWords":[],"peopleInVerse":["Barnabas"]},"14":{"text":"But when I saw that they walked not uprightly according to the truth of the gospel, I said unto Peter before them all, If thou, being a Jew, livest after the manner of Gentiles, and not as do the Jews, why compellest thou the Gentiles to live as do the Jews?","ref":"Galatians 2:14","synthesized":"When I saw that they were not walking in line with the truth of the gospel, I said to Cephas in front of them all, “If you, who are a Jew, live like a Gentile and not like a Jew, how can you compel the Gentiles to live like Jews?”","sources":{"KJV":{"text":"But when I saw that they walked not uprightly according to the truth of the gospel, I said unto Peter before them all, If thou, being a Jew, livest after the manner of Gentiles, and not as do the Jews, why compellest thou the Gentiles to live as do the Jews?"},"BSB":{"text":"When I saw that they were not walking in line with the truth of the gospel, I said to Cephas in front of them all, “If you, who are a Jew, live like a Gentile and not like a Jew, how can you compel the Gentiles to live like Jews?”"}},"definableWords":["saw","truth","gospel","Jew","live","gentile"],"peopleInVerse":[]},"15":{"text":"We who are Jews by nature, and not sinners of the Gentiles,","ref":"Galatians 2:15","synthesized":"We who are Jews by birth and not Gentile “sinners”","sources":{"KJV":{"text":"We who are Jews by nature, and not sinners of the Gentiles,"},"BSB":{"text":"We who are Jews by birth and not Gentile “sinners”"}},"definableWords":["gentile"],"peopleInVerse":[]},"16":{"text":"Knowing that a man is not justified by the works of the law, but by the faith of Jesus Christ, even we have believed in Jesus Christ, that we might be justified by the faith of Christ, and not by the works of the law: for by the works of the law shall no flesh be justified.","ref":"Galatians 2:16","synthesized":"know that a man is not justified by works of the law, but by faith in Jesus Christ. So we, too, have believed in Christ Jesus, that we may be justified by faith in Christ and not by works of the law, because by works of the law no one will be justified.","sources":{"KJV":{"text":"Knowing that a man is not justified by the works of the law, but by the faith of Jesus Christ, even we have believed in Jesus Christ, that we might be justified by the faith of Christ, and not by the works of the law: for by the works of the law shall no flesh be justified."},"BSB":{"text":"know that a man is not justified by works of the law, but by faith in Jesus Christ. So we, too, have believed in Christ Jesus, that we may be justified by faith in Christ and not by works of the law, because by works of the law no one will be justified."}},"definableWords":["man","works","law","faith","Christ","believed","one"],"peopleInVerse":["Jesus"]},"17":{"text":"But if, while we seek to be justified by Christ, we ourselves also are found sinners, is therefore Christ the minister of sin? God forbid.","ref":"Galatians 2:17","synthesized":"But if, while we seek to be justified in Christ, we ourselves are found to be sinners, does that make Christ a minister of sin? Certainly not!","sources":{"KJV":{"text":"But if, while we seek to be justified by Christ, we ourselves also are found sinners, is therefore Christ the minister of sin? God forbid."},"BSB":{"text":"But if, while we seek to be justified in Christ, we ourselves are found to be sinners, does that make Christ a minister of sin? Certainly not!"}},"definableWords":["seek","Christ","make","sin"],"peopleInVerse":[]},"18":{"text":"For if I build again the things which I destroyed, I make myself a transgressor.","ref":"Galatians 2:18","synthesized":"If I rebuild what I have already torn down, I prove myself to be a lawbreaker.","sources":{"KJV":{"text":"For if I build again the things which I destroyed, I make myself a transgressor."},"BSB":{"text":"If I rebuild what I have already torn down, I prove myself to be a lawbreaker."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"For I through the law am dead to the law, that I might live unto God.","ref":"Galatians 2:19","synthesized":"For through the law I died to the law so that I might live to God.","sources":{"KJV":{"text":"For I through the law am dead to the law, that I might live unto God."},"BSB":{"text":"For through the law I died to the law so that I might live to God."}},"definableWords":["law","live","God"],"peopleInVerse":[]},"20":{"text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me.","ref":"Galatians 2:20","synthesized":"I have been crucified with Christ, and I no longer live, but Christ lives in me. The life I live in the body, I live by faith in the Son of God, who loved me and gave Himself up for me.","sources":{"KJV":{"text":"I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me."},"BSB":{"text":"I have been crucified with Christ, and I no longer live, but Christ lives in me. The life I live in the body, I live by faith in the Son of God, who loved me and gave Himself up for me."}},"definableWords":["Christ","live","life","faith","Son","God"],"peopleInVerse":[]},"21":{"text":"I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain.","ref":"Galatians 2:21","synthesized":"I do not set aside the grace of God. For if righteousness comes through the law, Christ died for nothing.","sources":{"KJV":{"text":"I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain."},"BSB":{"text":"I do not set aside the grace of God. For if righteousness comes through the law, Christ died for nothing."}},"definableWords":["grace","God","righteousness","law","Christ"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"BY FAITH, NOT BY THE LAW","verses":{"1":{"text":"O foolish Galatians, who hath bewitched you, that ye should not obey the truth, before whose eyes Jesus Christ hath been evidently set forth, crucified among you?","ref":"Galatians 3:1","synthesized":"O foolish Galatians! Who has bewitched you? Before your very eyes Jesus Christ was clearly portrayed as crucified.","sources":{"KJV":{"text":"O foolish Galatians, who hath bewitched you, that ye should not obey the truth, before whose eyes Jesus Christ hath been evidently set forth, crucified among you?"},"BSB":{"text":"O foolish Galatians! Who has bewitched you? Before your very eyes Jesus Christ was clearly portrayed as crucified."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"2":{"text":"This only would I learn of you, Received ye the Spirit by the works of the law, or by the hearing of faith?","ref":"Galatians 3:2","synthesized":"I would like to learn just one thing from you: Did you receive the Spirit by works of the law, or by hearing with faith?","sources":{"KJV":{"text":"This only would I learn of you, Received ye the Spirit by the works of the law, or by the hearing of faith?"},"BSB":{"text":"I would like to learn just one thing from you: Did you receive the Spirit by works of the law, or by hearing with faith?"}},"definableWords":["one","Spirit","works","law","or","faith"],"peopleInVerse":[]},"3":{"text":"Are ye so foolish? having begun in the Spirit, are ye now made perfect by the flesh?","ref":"Galatians 3:3","synthesized":"Are you so foolish? After starting in the Spirit, are you now finishing in the flesh?","sources":{"KJV":{"text":"Are ye so foolish? having begun in the Spirit, are ye now made perfect by the flesh?"},"BSB":{"text":"Are you so foolish? After starting in the Spirit, are you now finishing in the flesh?"}},"definableWords":["Spirit","flesh"],"peopleInVerse":[]},"4":{"text":"Have ye suffered so many things in vain? if it be yet in vain.","ref":"Galatians 3:4","synthesized":"Have you suffered so much for nothing, if it really was for nothing?","sources":{"KJV":{"text":"Have ye suffered so many things in vain? if it be yet in vain."},"BSB":{"text":"Have you suffered so much for nothing, if it really was for nothing?"}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"He therefore that ministereth to you the Spirit, and worketh miracles among you, doeth he it by the works of the law, or by the hearing of faith?","ref":"Galatians 3:5","synthesized":"Does God lavish His Spirit on you and work miracles among you because you practice the law, or because you hear and believe?","sources":{"KJV":{"text":"He therefore that ministereth to you the Spirit, and worketh miracles among you, doeth he it by the works of the law, or by the hearing of faith?"},"BSB":{"text":"Does God lavish His Spirit on you and work miracles among you because you practice the law, or because you hear and believe?"}},"definableWords":["God","Spirit","work","law","or","hear"],"peopleInVerse":[]},"6":{"text":"Even as Abraham believed God, and it was accounted to him for righteousness.","ref":"Galatians 3:6","synthesized":"So also, “Abraham believed God, and it was credited to him as righteousness.”","sources":{"KJV":{"text":"Even as Abraham believed God, and it was accounted to him for righteousness."},"BSB":{"text":"So also, “Abraham believed God, and it was credited to him as righteousness.”"}},"definableWords":["Abraham","believed","God","righteousness"],"peopleInVerse":["Abraham"]},"7":{"text":"Know ye therefore that they which are of faith, the same are the children of Abraham.","ref":"Galatians 3:7","synthesized":"Understand, then, that those who have faith are sons of Abraham.","sources":{"KJV":{"text":"Know ye therefore that they which are of faith, the same are the children of Abraham."},"BSB":{"text":"Understand, then, that those who have faith are sons of Abraham."}},"definableWords":["faith","sons","Abraham"],"peopleInVerse":["Abraham"]},"8":{"text":"And the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed.","ref":"Galatians 3:8","synthesized":"The Scripture foresaw that God would justify the Gentiles by faith, and foretold the gospel to Abraham: “All nations will be blessed through you.”","sources":{"KJV":{"text":"And the scripture, foreseeing that God would justify the heathen through faith, preached before the gospel unto Abraham, saying, In thee shall all nations be blessed."},"BSB":{"text":"The Scripture foresaw that God would justify the Gentiles by faith, and foretold the gospel to Abraham: “All nations will be blessed through you.”"}},"definableWords":["God","faith","gospel","Abraham","nations","blessed"],"peopleInVerse":["Abraham"]},"9":{"text":"So then they which be of faith are blessed with faithful Abraham.","ref":"Galatians 3:9","synthesized":"So those who have faith are blessed along with Abraham, the man of faith.","sources":{"KJV":{"text":"So then they which be of faith are blessed with faithful Abraham."},"BSB":{"text":"So those who have faith are blessed along with Abraham, the man of faith."}},"definableWords":["faith","blessed","Abraham","man"],"peopleInVerse":["Abraham"]},"10":{"text":"For as many as are of the works of the law are under the curse: for it is written, Cursed is every one that continueth not in all things which are written in the book of the law to do them.","ref":"Galatians 3:10","synthesized":"All who rely on works of the law are under a curse. For it is written: “Cursed is everyone who does not continue to do everything written in the Book of the Law.”","sources":{"KJV":{"text":"For as many as are of the works of the law are under the curse: for it is written, Cursed is every one that continueth not in all things which are written in the book of the law to do them."},"BSB":{"text":"All who rely on works of the law are under a curse. For it is written: “Cursed is everyone who does not continue to do everything written in the Book of the Law.”"}},"definableWords":["works","law","curse","cursed"],"peopleInVerse":[]},"11":{"text":"But that no man is justified by the law in the sight of God, it is evident: for, The just shall live by faith.","ref":"Galatians 3:11","synthesized":"Now it is clear that no one is justified before God by the law, because, “The righteous will live by faith.”","sources":{"KJV":{"text":"But that no man is justified by the law in the sight of God, it is evident: for, The just shall live by faith."},"BSB":{"text":"Now it is clear that no one is justified before God by the law, because, “The righteous will live by faith.”"}},"definableWords":["one","God","law","righteous","live","faith"],"peopleInVerse":[]},"12":{"text":"And the law is not of faith: but, The man that doeth them shall live in them.","ref":"Galatians 3:12","synthesized":"The law, however, is not based on faith; on the contrary, “The man who does these things will live by them.”","sources":{"KJV":{"text":"And the law is not of faith: but, The man that doeth them shall live in them."},"BSB":{"text":"The law, however, is not based on faith; on the contrary, “The man who does these things will live by them.”"}},"definableWords":["law","faith","man","live"],"peopleInVerse":[]},"13":{"text":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree:","ref":"Galatians 3:13","synthesized":"Christ redeemed us from the curse of the law by becoming a curse for us. For it is written: “Cursed is everyone who is hung on a tree.”","sources":{"KJV":{"text":"Christ hath redeemed us from the curse of the law, being made a curse for us: for it is written, Cursed is every one that hangeth on a tree:"},"BSB":{"text":"Christ redeemed us from the curse of the law by becoming a curse for us. For it is written: “Cursed is everyone who is hung on a tree.”"}},"definableWords":["Christ","curse","law","cursed","tree"],"peopleInVerse":[]},"14":{"text":"That the blessing of Abraham might come on the Gentiles through Jesus Christ; that we might receive the promise of the Spirit through faith.","ref":"Galatians 3:14","synthesized":"He redeemed us in order that the blessing promised to Abraham would come to the Gentiles in Christ Jesus, so that by faith we might receive the promise of the Spirit.","sources":{"KJV":{"text":"That the blessing of Abraham might come on the Gentiles through Jesus Christ; that we might receive the promise of the Spirit through faith."},"BSB":{"text":"He redeemed us in order that the blessing promised to Abraham would come to the Gentiles in Christ Jesus, so that by faith we might receive the promise of the Spirit."}},"definableWords":["blessing","Abraham","Christ","faith","promise","Spirit"],"peopleInVerse":["Abraham","Jesus"]},"15":{"text":"Brethren, I speak after the manner of men; Though it be but a man’s covenant, yet if it be confirmed, no man disannulleth, or addeth thereto.","ref":"Galatians 3:15","synthesized":"Brothers, let me put this in human terms. Even a human covenant, once it is ratified, cannot be canceled or amended.","sources":{"KJV":{"text":"Brethren, I speak after the manner of men; Though it be but a man’s covenant, yet if it be confirmed, no man disannulleth, or addeth thereto."},"BSB":{"text":"Brothers, let me put this in human terms. Even a human covenant, once it is ratified, cannot be canceled or amended."}},"definableWords":["covenant","or"],"peopleInVerse":[]},"16":{"text":"Now to Abraham and his seed were the promises made. He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ.","ref":"Galatians 3:16","synthesized":"The promises were spoken to Abraham and to his seed. The Scripture does not say, “and to seeds,” meaning many, but “and to your seed,” meaning One, who is Christ.","sources":{"KJV":{"text":"Now to Abraham and his seed were the promises made. He saith not, And to seeds, as of many; but as of one, And to thy seed, which is Christ."},"BSB":{"text":"The promises were spoken to Abraham and to his seed. The Scripture does not say, “and to seeds,” meaning many, but “and to your seed,” meaning One, who is Christ."}},"definableWords":["Abraham","seed","one","Christ"],"peopleInVerse":["Abraham"]},"17":{"text":"And this I say, that the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul, that it should make the promise of none effect.","ref":"Galatians 3:17","synthesized":"What I mean is this: The law that came 430 years later does not revoke the covenant previously established by God, so as to nullify the promise.","sources":{"KJV":{"text":"And this I say, that the covenant, that was confirmed before of God in Christ, the law, which was four hundred and thirty years after, cannot disannul, that it should make the promise of none effect."},"BSB":{"text":"What I mean is this: The law that came 430 years later does not revoke the covenant previously established by God, so as to nullify the promise."}},"definableWords":["law","years","covenant","God","promise"],"peopleInVerse":[]},"18":{"text":"For if the inheritance be of the law, it is no more of promise: but God gave it to Abraham by promise.","ref":"Galatians 3:18","synthesized":"For if the inheritance depends on the law, then it no longer depends on a promise; but God freely granted it to Abraham through a promise.","sources":{"KJV":{"text":"For if the inheritance be of the law, it is no more of promise: but God gave it to Abraham by promise."},"BSB":{"text":"For if the inheritance depends on the law, then it no longer depends on a promise; but God freely granted it to Abraham through a promise."}},"definableWords":["law","promise","God","Abraham"],"peopleInVerse":["Abraham"]},"19":{"text":"Wherefore then serveth the law? It was added because of transgressions, till the seed should come to whom the promise was made; and it was ordained by angels in the hand of a mediator.","ref":"Galatians 3:19","synthesized":"Why then was the law given? It was added because of transgressions, until the arrival of the seed to whom the promise referred. It was administered through angels by a mediator.","sources":{"KJV":{"text":"Wherefore then serveth the law? It was added because of transgressions, till the seed should come to whom the promise was made; and it was ordained by angels in the hand of a mediator."},"BSB":{"text":"Why then was the law given? It was added because of transgressions, until the arrival of the seed to whom the promise referred. It was administered through angels by a mediator."}},"definableWords":["law","seed","promise"],"peopleInVerse":[]},"20":{"text":"Now a mediator is not a mediator of one, but God is one.","ref":"Galatians 3:20","synthesized":"A mediator is unnecessary, however, for only one party; but God is one.","sources":{"KJV":{"text":"Now a mediator is not a mediator of one, but God is one."},"BSB":{"text":"A mediator is unnecessary, however, for only one party; but God is one."}},"definableWords":["one","God"],"peopleInVerse":[]},"21":{"text":"Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law.","ref":"Galatians 3:21","synthesized":"Is the law, then, opposed to the promises of God? Certainly not! For if a law had been given that could impart life, then righteousness would certainly have come from the law.","sources":{"KJV":{"text":"Is the law then against the promises of God? God forbid: for if there had been a law given which could have given life, verily righteousness should have been by the law."},"BSB":{"text":"Is the law, then, opposed to the promises of God? Certainly not! For if a law had been given that could impart life, then righteousness would certainly have come from the law."}},"definableWords":["law","God","life","righteousness"],"peopleInVerse":[]},"22":{"text":"But the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe.","ref":"Galatians 3:22","synthesized":"But the Scripture pronounces all things confined by sin, so that by faith in Jesus Christ the promise might be given to those who believe.","sources":{"KJV":{"text":"But the scripture hath concluded all under sin, that the promise by faith of Jesus Christ might be given to them that believe."},"BSB":{"text":"But the Scripture pronounces all things confined by sin, so that by faith in Jesus Christ the promise might be given to those who believe."}},"definableWords":["sin","faith","Christ","promise"],"peopleInVerse":["Jesus"]},"23":{"text":"But before faith came, we were kept under the law, shut up unto the faith which should afterwards be revealed.","ref":"Galatians 3:23","synthesized":"Before this faith came, we were held in custody under the law, locked up until faith should be revealed.","sources":{"KJV":{"text":"But before faith came, we were kept under the law, shut up unto the faith which should afterwards be revealed."},"BSB":{"text":"Before this faith came, we were held in custody under the law, locked up until faith should be revealed."}},"definableWords":["faith","law"],"peopleInVerse":[]},"24":{"text":"Wherefore the law was our schoolmaster to bring us unto Christ, that we might be justified by faith.","ref":"Galatians 3:24","synthesized":"So the law became our guardian to lead us to Christ, that we might be justified by faith.","sources":{"KJV":{"text":"Wherefore the law was our schoolmaster to bring us unto Christ, that we might be justified by faith."},"BSB":{"text":"So the law became our guardian to lead us to Christ, that we might be justified by faith."}},"definableWords":["law","Christ","faith"],"peopleInVerse":[]},"25":{"text":"But after that faith is come, we are no longer under a schoolmaster.","ref":"Galatians 3:25","synthesized":"Now that faith has come, we are no longer under a guardian.","sources":{"KJV":{"text":"But after that faith is come, we are no longer under a schoolmaster."},"BSB":{"text":"Now that faith has come, we are no longer under a guardian."}},"definableWords":["faith"],"peopleInVerse":[]},"26":{"text":"For ye are all the children of God by faith in Christ Jesus.","ref":"Galatians 3:26","synthesized":"You are all sons of God through faith in Christ Jesus.","sources":{"KJV":{"text":"For ye are all the children of God by faith in Christ Jesus."},"BSB":{"text":"You are all sons of God through faith in Christ Jesus."}},"definableWords":["sons","God","faith","Christ"],"peopleInVerse":["Jesus"]},"27":{"text":"For as many of you as have been baptized into Christ have put on Christ.","ref":"Galatians 3:27","synthesized":"For all of you who were baptized into Christ have clothed yourselves with Christ.","sources":{"KJV":{"text":"For as many of you as have been baptized into Christ have put on Christ."},"BSB":{"text":"For all of you who were baptized into Christ have clothed yourselves with Christ."}},"definableWords":["Christ"],"peopleInVerse":[]},"28":{"text":"There is neither Jew nor Greek, there is neither bond nor free, there is neither male nor female: for ye are all one in Christ Jesus.","ref":"Galatians 3:28","synthesized":"There is neither Jew nor Greek, slave nor free, male nor female, for you are all one in Christ Jesus.","sources":{"KJV":{"text":"There is neither Jew nor Greek, there is neither bond nor free, there is neither male nor female: for ye are all one in Christ Jesus."},"BSB":{"text":"There is neither Jew nor Greek, slave nor free, male nor female, for you are all one in Christ Jesus."}},"definableWords":["Jew","Greek","male","female","one","Christ"],"peopleInVerse":["Jesus"]},"29":{"text":"And if ye be Christ’s, then are ye Abraham’s seed, and heirs according to the promise.","ref":"Galatians 3:29","synthesized":"And if you belong to Christ, then you are Abraham’s seed and heirs according to the promise.","sources":{"KJV":{"text":"And if ye be Christ’s, then are ye Abraham’s seed, and heirs according to the promise."},"BSB":{"text":"And if you belong to Christ, then you are Abraham’s seed and heirs according to the promise."}},"definableWords":["Christ","Abraham","seed","promise"],"peopleInVerse":["Abraham"]}}},"4":{"chapter":"4","title":"WHEN THE FULNESS OF TIME WAS COME","verses":{"1":{"text":"Now I say, That the heir, as long as he is a child, differeth nothing from a servant, though he be lord of all;","ref":"Galatians 4:1","synthesized":"What I am saying is that as long as the heir is a child, he is no different from a slave, although he is the owner of everything.","sources":{"KJV":{"text":"Now I say, That the heir, as long as he is a child, differeth nothing from a servant, though he be lord of all;"},"BSB":{"text":"What I am saying is that as long as the heir is a child, he is no different from a slave, although he is the owner of everything."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"But is under tutors and governors until the time appointed of the father.","ref":"Galatians 4:2","synthesized":"He is subject to guardians and trustees until the date set by his father.","sources":{"KJV":{"text":"But is under tutors and governors until the time appointed of the father."},"BSB":{"text":"He is subject to guardians and trustees until the date set by his father."}},"definableWords":["father"],"peopleInVerse":[]},"3":{"text":"Even so we, when we were children, were in bondage under the elements of the world:","ref":"Galatians 4:3","synthesized":"So also, when we were children, we were enslaved under the basic principles of the world.","sources":{"KJV":{"text":"Even so we, when we were children, were in bondage under the elements of the world:"},"BSB":{"text":"So also, when we were children, we were enslaved under the basic principles of the world."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law,","ref":"Galatians 4:4","synthesized":"But when the time had fully come, God sent His Son, born of a woman, born under the law,","sources":{"KJV":{"text":"But when the fulness of the time was come, God sent forth his Son, made of a woman, made under the law,"},"BSB":{"text":"But when the time had fully come, God sent His Son, born of a woman, born under the law,"}},"definableWords":["God","Son","woman","law"],"peopleInVerse":[]},"5":{"text":"To redeem them that were under the law, that we might receive the adoption of sons.","ref":"Galatians 4:5","synthesized":"to redeem those under the law, that we might receive our adoption as sons.","sources":{"KJV":{"text":"To redeem them that were under the law, that we might receive the adoption of sons."},"BSB":{"text":"to redeem those under the law, that we might receive our adoption as sons."}},"definableWords":["law","sons"],"peopleInVerse":[]},"6":{"text":"And because ye are sons, God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father.","ref":"Galatians 4:6","synthesized":"And because you are sons, God sent the Spirit of His Son into our hearts, crying out, “Abba, Father!”","sources":{"KJV":{"text":"And because ye are sons, God hath sent forth the Spirit of his Son into your hearts, crying, Abba, Father."},"BSB":{"text":"And because you are sons, God sent the Spirit of His Son into our hearts, crying out, “Abba, Father!”"}},"definableWords":["sons","God","Spirit","Son","Father"],"peopleInVerse":[]},"7":{"text":"Wherefore thou art no more a servant, but a son; and if a son, then an heir of God through Christ.","ref":"Galatians 4:7","synthesized":"So you are no longer a slave, but a son; and since you are a son, you are also an heir through God.","sources":{"KJV":{"text":"Wherefore thou art no more a servant, but a son; and if a son, then an heir of God through Christ."},"BSB":{"text":"So you are no longer a slave, but a son; and since you are a son, you are also an heir through God."}},"definableWords":["son","Son","God"],"peopleInVerse":[]},"8":{"text":"Howbeit then, when ye knew not God, ye did service unto them which by nature are no gods.","ref":"Galatians 4:8","synthesized":"Formerly, when you did not know God, you were slaves to those who by nature are not gods.","sources":{"KJV":{"text":"Howbeit then, when ye knew not God, ye did service unto them which by nature are no gods."},"BSB":{"text":"Formerly, when you did not know God, you were slaves to those who by nature are not gods."}},"definableWords":["God"],"peopleInVerse":[]},"9":{"text":"But now, after that ye have known God, or rather are known of God, how turn ye again to the weak and beggarly elements, whereunto ye desire again to be in bondage?","ref":"Galatians 4:9","synthesized":"But now that you know God, or rather are known by God, how is it that you are turning back to those weak and worthless principles? Do you wish to be enslaved by them all over again?","sources":{"KJV":{"text":"But now, after that ye have known God, or rather are known of God, how turn ye again to the weak and beggarly elements, whereunto ye desire again to be in bondage?"},"BSB":{"text":"But now that you know God, or rather are known by God, how is it that you are turning back to those weak and worthless principles? Do you wish to be enslaved by them all over again?"}},"definableWords":["God","or"],"peopleInVerse":[]},"10":{"text":"Ye observe days, and months, and times, and years.","ref":"Galatians 4:10","synthesized":"You are observing special days and months and seasons and years!","sources":{"KJV":{"text":"Ye observe days, and months, and times, and years."},"BSB":{"text":"You are observing special days and months and seasons and years!"}},"definableWords":["days","years"],"peopleInVerse":[]},"11":{"text":"I am afraid of you, lest I have bestowed upon you labour in vain.","ref":"Galatians 4:11","synthesized":"I fear for you, that my efforts for you may have been in vain.","sources":{"KJV":{"text":"I am afraid of you, lest I have bestowed upon you labour in vain."},"BSB":{"text":"I fear for you, that my efforts for you may have been in vain."}},"definableWords":["fear"],"peopleInVerse":[]},"12":{"text":"Brethren, I beseech you, be as I am; for I am as ye are: ye have not injured me at all.","ref":"Galatians 4:12","synthesized":"I beg you, brothers, become like me, for I became like you. You have done me no wrong.","sources":{"KJV":{"text":"Brethren, I beseech you, be as I am; for I am as ye are: ye have not injured me at all."},"BSB":{"text":"I beg you, brothers, become like me, for I became like you. You have done me no wrong."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Ye know how through infirmity of the flesh I preached the gospel unto you at the first.","ref":"Galatians 4:13","synthesized":"You know that it was because of an illness that I first preached the gospel to you.","sources":{"KJV":{"text":"Ye know how through infirmity of the flesh I preached the gospel unto you at the first."},"BSB":{"text":"You know that it was because of an illness that I first preached the gospel to you."}},"definableWords":["gospel"],"peopleInVerse":[]},"14":{"text":"And my temptation which was in my flesh ye despised not, nor rejected; but received me as an angel of God, even as Christ Jesus.","ref":"Galatians 4:14","synthesized":"And although my illness was a trial to you, you did not despise or reject me. Instead, you welcomed me as if I were an angel of God, as if I were Christ Jesus Himself.","sources":{"KJV":{"text":"And my temptation which was in my flesh ye despised not, nor rejected; but received me as an angel of God, even as Christ Jesus."},"BSB":{"text":"And although my illness was a trial to you, you did not despise or reject me. Instead, you welcomed me as if I were an angel of God, as if I were Christ Jesus Himself."}},"definableWords":["or","angel","God","Christ"],"peopleInVerse":["Jesus"]},"15":{"text":"Where is then the blessedness ye spake of? for I bear you record, that, if it had been possible, ye would have plucked out your own eyes, and have given them to me.","ref":"Galatians 4:15","synthesized":"What then has become of your blessing? For I can testify that, if it were possible, you would have torn out your eyes and given them to me.","sources":{"KJV":{"text":"Where is then the blessedness ye spake of? for I bear you record, that, if it had been possible, ye would have plucked out your own eyes, and have given them to me."},"BSB":{"text":"What then has become of your blessing? For I can testify that, if it were possible, you would have torn out your eyes and given them to me."}},"definableWords":["blessing"],"peopleInVerse":[]},"16":{"text":"Am I therefore become your enemy, because I tell you the truth?","ref":"Galatians 4:16","synthesized":"Have I now become your enemy by telling you the truth?","sources":{"KJV":{"text":"Am I therefore become your enemy, because I tell you the truth?"},"BSB":{"text":"Have I now become your enemy by telling you the truth?"}},"definableWords":["truth"],"peopleInVerse":[]},"17":{"text":"They zealously affect you, but not well; yea, they would exclude you, that ye might affect them.","ref":"Galatians 4:17","synthesized":"Those people are zealous for you, but not in a good way. Instead, they want to isolate you from us, so that you may be zealous for them.","sources":{"KJV":{"text":"They zealously affect you, but not well; yea, they would exclude you, that ye might affect them."},"BSB":{"text":"Those people are zealous for you, but not in a good way. Instead, they want to isolate you from us, so that you may be zealous for them."}},"definableWords":["people","good","way"],"peopleInVerse":[]},"18":{"text":"But it is good to be zealously affected always in a good thing, and not only when I am present with you.","ref":"Galatians 4:18","synthesized":"Nevertheless, it is good to be zealous if it serves a noble purpose—at any time, and not only when I am with you.","sources":{"KJV":{"text":"But it is good to be zealously affected always in a good thing, and not only when I am present with you."},"BSB":{"text":"Nevertheless, it is good to be zealous if it serves a noble purpose—at any time, and not only when I am with you."}},"definableWords":["good"],"peopleInVerse":[]},"19":{"text":"My little children, of whom I travail in birth again until Christ be formed in you,","ref":"Galatians 4:19","synthesized":"My children, for whom I am again in the pains of childbirth until Christ is formed in you,","sources":{"KJV":{"text":"My little children, of whom I travail in birth again until Christ be formed in you,"},"BSB":{"text":"My children, for whom I am again in the pains of childbirth until Christ is formed in you,"}},"definableWords":["Christ","formed"],"peopleInVerse":[]},"20":{"text":"I desire to be present with you now, and to change my voice; for I stand in doubt of you.","ref":"Galatians 4:20","synthesized":"how I wish I could be with you now and change my tone, because I am perplexed about you.","sources":{"KJV":{"text":"I desire to be present with you now, and to change my voice; for I stand in doubt of you."},"BSB":{"text":"how I wish I could be with you now and change my tone, because I am perplexed about you."}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Tell me, ye that desire to be under the law, do ye not hear the law?","ref":"Galatians 4:21","synthesized":"Tell me, you who want to be under the law, do you not understand what the law says?","sources":{"KJV":{"text":"Tell me, ye that desire to be under the law, do ye not hear the law?"},"BSB":{"text":"Tell me, you who want to be under the law, do you not understand what the law says?"}},"definableWords":["law"],"peopleInVerse":[]},"22":{"text":"For it is written, that Abraham had two sons, the one by a bondmaid, the other by a freewoman.","ref":"Galatians 4:22","synthesized":"For it is written that Abraham had two sons, one by the slave woman and the other by the free woman.","sources":{"KJV":{"text":"For it is written, that Abraham had two sons, the one by a bondmaid, the other by a freewoman."},"BSB":{"text":"For it is written that Abraham had two sons, one by the slave woman and the other by the free woman."}},"definableWords":["Abraham","sons","one","woman"],"peopleInVerse":["Abraham"]},"23":{"text":"But he who was of the bondwoman was born after the flesh; but he of the freewoman was by promise.","ref":"Galatians 4:23","synthesized":"His son by the slave woman was born according to the flesh, but his son by the free woman was born through the promise.","sources":{"KJV":{"text":"But he who was of the bondwoman was born after the flesh; but he of the freewoman was by promise."},"BSB":{"text":"His son by the slave woman was born according to the flesh, but his son by the free woman was born through the promise."}},"definableWords":["son","woman","flesh","Son","promise"],"peopleInVerse":[]},"24":{"text":"Which things are an allegory: for these are the two covenants; the one from the mount Sinai, which gendereth to bondage, which is Agar.","ref":"Galatians 4:24","synthesized":"These things serve as illustrations, for the women represent two covenants. One covenant is from Mount Sinai and bears children into slavery: This is Hagar.","sources":{"KJV":{"text":"Which things are an allegory: for these are the two covenants; the one from the mount Sinai, which gendereth to bondage, which is Agar."},"BSB":{"text":"These things serve as illustrations, for the women represent two covenants. One covenant is from Mount Sinai and bears children into slavery: This is Hagar."}},"definableWords":["women","one","covenant","Hagar"],"peopleInVerse":["Hagar"]},"25":{"text":"For this Agar is mount Sinai in Arabia, and answereth to Jerusalem which now is, and is in bondage with her children.","ref":"Galatians 4:25","synthesized":"Now Hagar stands for Mount Sinai in Arabia and corresponds to the present-day Jerusalem, because she is in slavery with her children.","sources":{"KJV":{"text":"For this Agar is mount Sinai in Arabia, and answereth to Jerusalem which now is, and is in bondage with her children."},"BSB":{"text":"Now Hagar stands for Mount Sinai in Arabia and corresponds to the present-day Jerusalem, because she is in slavery with her children."}},"definableWords":["Hagar","day","Jerusalem"],"peopleInVerse":["Hagar"]},"26":{"text":"But Jerusalem which is above is free, which is the mother of us all.","ref":"Galatians 4:26","synthesized":"But the Jerusalem above is free, and she is our mother.","sources":{"KJV":{"text":"But Jerusalem which is above is free, which is the mother of us all."},"BSB":{"text":"But the Jerusalem above is free, and she is our mother."}},"definableWords":["Jerusalem","mother"],"peopleInVerse":[]},"27":{"text":"For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband.","ref":"Galatians 4:27","synthesized":"For it is written:  “Rejoice, O barren woman, who bears no children; break forth and cry aloud, you who have never travailed; because more are the children of the desolate woman than of her who has a husband.”","sources":{"KJV":{"text":"For it is written, Rejoice, thou barren that bearest not; break forth and cry, thou that travailest not: for the desolate hath many more children than she which hath an husband."},"BSB":{"text":"For it is written:  “Rejoice, O barren woman, who bears no children; break forth and cry aloud, you who have never travailed; because more are the children of the desolate woman than of her who has a husband.”"}},"definableWords":["woman","husband"],"peopleInVerse":[]},"28":{"text":"Now we, brethren, as Isaac was, are the children of promise.","ref":"Galatians 4:28","synthesized":"Now you, brothers, like Isaac, are children of promise.","sources":{"KJV":{"text":"Now we, brethren, as Isaac was, are the children of promise."},"BSB":{"text":"Now you, brothers, like Isaac, are children of promise."}},"definableWords":["Isaac","promise"],"peopleInVerse":["Isaac"]},"29":{"text":"But as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now.","ref":"Galatians 4:29","synthesized":"At that time, however, the son born by the flesh persecuted the son born by the Spirit. It is the same now.","sources":{"KJV":{"text":"But as then he that was born after the flesh persecuted him that was born after the Spirit, even so it is now."},"BSB":{"text":"At that time, however, the son born by the flesh persecuted the son born by the Spirit. It is the same now."}},"definableWords":["son","flesh","Son","Spirit"],"peopleInVerse":[]},"30":{"text":"Nevertheless what saith the scripture? Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman.","ref":"Galatians 4:30","synthesized":"But what does the Scripture say? “Expel the slave woman and her son, for the slave woman’s son will never share in the inheritance with the free woman’s son.”","sources":{"KJV":{"text":"Nevertheless what saith the scripture? Cast out the bondwoman and her son: for the son of the bondwoman shall not be heir with the son of the freewoman."},"BSB":{"text":"But what does the Scripture say? “Expel the slave woman and her son, for the slave woman’s son will never share in the inheritance with the free woman’s son.”"}},"definableWords":["woman","son","Son"],"peopleInVerse":[]},"31":{"text":"So then, brethren, we are not children of the bondwoman, but of the free.","ref":"Galatians 4:31","synthesized":"Therefore, brothers, we are not children of the slave woman, but of the free woman.","sources":{"KJV":{"text":"So then, brethren, we are not children of the bondwoman, but of the free."},"BSB":{"text":"Therefore, brothers, we are not children of the slave woman, but of the free woman."}},"definableWords":["woman"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"THE FRUIT OF THE SPIRIT","verses":{"1":{"text":"Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage.","ref":"Galatians 5:1","synthesized":"It is for freedom that Christ has set us free. Stand firm, then, and do not be encumbered once more by a yoke of slavery.","sources":{"KJV":{"text":"Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage."},"BSB":{"text":"It is for freedom that Christ has set us free. Stand firm, then, and do not be encumbered once more by a yoke of slavery."}},"definableWords":["Christ","stand"],"peopleInVerse":[]},"2":{"text":"Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing.","ref":"Galatians 5:2","synthesized":"Take notice: I, Paul, tell you that if you let yourselves be circumcised, Christ will be of no value to you at all.","sources":{"KJV":{"text":"Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing."},"BSB":{"text":"Take notice: I, Paul, tell you that if you let yourselves be circumcised, Christ will be of no value to you at all."}},"definableWords":["circumcised","Christ"],"peopleInVerse":["Paul"]},"3":{"text":"For I testify again to every man that is circumcised, that he is a debtor to do the whole law.","ref":"Galatians 5:3","synthesized":"Again I testify to every man who gets himself circumcised that he is obligated to obey the whole law.","sources":{"KJV":{"text":"For I testify again to every man that is circumcised, that he is a debtor to do the whole law."},"BSB":{"text":"Again I testify to every man who gets himself circumcised that he is obligated to obey the whole law."}},"definableWords":["man","circumcised","law"],"peopleInVerse":[]},"4":{"text":"Christ is become of no effect unto you, whosoever of you are justified by the law; ye are fallen from grace.","ref":"Galatians 5:4","synthesized":"You who are trying to be justified by the law have been severed from Christ; you have fallen away from grace.","sources":{"KJV":{"text":"Christ is become of no effect unto you, whosoever of you are justified by the law; ye are fallen from grace."},"BSB":{"text":"You who are trying to be justified by the law have been severed from Christ; you have fallen away from grace."}},"definableWords":["law","Christ","grace"],"peopleInVerse":[]},"5":{"text":"For we through the Spirit wait for the hope of righteousness by faith.","ref":"Galatians 5:5","synthesized":"But by faith we eagerly await through the Spirit the hope of righteousness.","sources":{"KJV":{"text":"For we through the Spirit wait for the hope of righteousness by faith."},"BSB":{"text":"But by faith we eagerly await through the Spirit the hope of righteousness."}},"definableWords":["faith","Spirit","hope","righteousness"],"peopleInVerse":[]},"6":{"text":"For in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love.","ref":"Galatians 5:6","synthesized":"For in Christ Jesus neither circumcision nor uncircumcision has any value. All that matters is faith, expressed through love.","sources":{"KJV":{"text":"For in Jesus Christ neither circumcision availeth any thing, nor uncircumcision; but faith which worketh by love."},"BSB":{"text":"For in Christ Jesus neither circumcision nor uncircumcision has any value. All that matters is faith, expressed through love."}},"definableWords":["Christ","circumcision","faith","love"],"peopleInVerse":["Jesus"]},"7":{"text":"Ye did run well; who did hinder you that ye should not obey the truth?","ref":"Galatians 5:7","synthesized":"You were running so well. Who has obstructed you from obeying the truth?","sources":{"KJV":{"text":"Ye did run well; who did hinder you that ye should not obey the truth?"},"BSB":{"text":"You were running so well. Who has obstructed you from obeying the truth?"}},"definableWords":["truth"],"peopleInVerse":[]},"8":{"text":"This persuasion cometh not of him that calleth you.","ref":"Galatians 5:8","synthesized":"Such persuasion does not come from the One who calls you.","sources":{"KJV":{"text":"This persuasion cometh not of him that calleth you."},"BSB":{"text":"Such persuasion does not come from the One who calls you."}},"definableWords":["one"],"peopleInVerse":[]},"9":{"text":"A little leaven leaveneth the whole lump.","ref":"Galatians 5:9","synthesized":"A little leaven works through the whole batch of dough.","sources":{"KJV":{"text":"A little leaven leaveneth the whole lump."},"BSB":{"text":"A little leaven works through the whole batch of dough."}},"definableWords":["works"],"peopleInVerse":[]},"10":{"text":"I have confidence in you through the Lord, that ye will be none otherwise minded: but he that troubleth you shall bear his judgment, whosoever he be.","ref":"Galatians 5:10","synthesized":"I am confident in the Lord that you will take no other view. The one who is troubling you will bear the judgment, whoever he may be.","sources":{"KJV":{"text":"I have confidence in you through the Lord, that ye will be none otherwise minded: but he that troubleth you shall bear his judgment, whosoever he be."},"BSB":{"text":"I am confident in the Lord that you will take no other view. The one who is troubling you will bear the judgment, whoever he may be."}},"definableWords":["Lord","one","judgment"],"peopleInVerse":[]},"11":{"text":"And I, brethren, if I yet preach circumcision, why do I yet suffer persecution? then is the offence of the cross ceased.","ref":"Galatians 5:11","synthesized":"Now, brothers, if I am still preaching circumcision, why am I still being persecuted? In that case the offense of the cross has been abolished.","sources":{"KJV":{"text":"And I, brethren, if I yet preach circumcision, why do I yet suffer persecution? then is the offence of the cross ceased."},"BSB":{"text":"Now, brothers, if I am still preaching circumcision, why am I still being persecuted? In that case the offense of the cross has been abolished."}},"definableWords":["circumcision"],"peopleInVerse":[]},"12":{"text":"I would they were even cut off which trouble you.","ref":"Galatians 5:12","synthesized":"As for those who are agitating you, I wish they would proceed to emasculate themselves!","sources":{"KJV":{"text":"I would they were even cut off which trouble you."},"BSB":{"text":"As for those who are agitating you, I wish they would proceed to emasculate themselves!"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"For, brethren, ye have been called unto liberty; only use not liberty for an occasion to the flesh, but by love serve one another.","ref":"Galatians 5:13","synthesized":"For you, brothers, were called to freedom; but do not use your freedom as an opportunity for the flesh. Rather, serve one another in love.","sources":{"KJV":{"text":"For, brethren, ye have been called unto liberty; only use not liberty for an occasion to the flesh, but by love serve one another."},"BSB":{"text":"For you, brothers, were called to freedom; but do not use your freedom as an opportunity for the flesh. Rather, serve one another in love."}},"definableWords":["flesh","one","love"],"peopleInVerse":[]},"14":{"text":"For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself.","ref":"Galatians 5:14","synthesized":"The entire law is fulfilled in a single decree: “Love your neighbor as yourself.”","sources":{"KJV":{"text":"For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself."},"BSB":{"text":"The entire law is fulfilled in a single decree: “Love your neighbor as yourself.”"}},"definableWords":["law","love"],"peopleInVerse":[]},"15":{"text":"But if ye bite and devour one another, take heed that ye be not consumed one of another.","ref":"Galatians 5:15","synthesized":"But if you keep on biting and devouring one another, watch out, or you will be consumed by one another.","sources":{"KJV":{"text":"But if ye bite and devour one another, take heed that ye be not consumed one of another."},"BSB":{"text":"But if you keep on biting and devouring one another, watch out, or you will be consumed by one another."}},"definableWords":["keep","one","or"],"peopleInVerse":[]},"16":{"text":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh.","ref":"Galatians 5:16","synthesized":"So I say, walk by the Spirit, and you will not gratify the desires of the flesh.","sources":{"KJV":{"text":"This I say then, Walk in the Spirit, and ye shall not fulfil the lust of the flesh."},"BSB":{"text":"So I say, walk by the Spirit, and you will not gratify the desires of the flesh."}},"definableWords":["walk","Spirit","flesh"],"peopleInVerse":[]},"17":{"text":"For the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other: so that ye cannot do the things that ye would.","ref":"Galatians 5:17","synthesized":"For the flesh craves what is contrary to the Spirit, and the Spirit what is contrary to the flesh. They are opposed to each other, so that you do not do what you want.","sources":{"KJV":{"text":"For the flesh lusteth against the Spirit, and the Spirit against the flesh: and these are contrary the one to the other: so that ye cannot do the things that ye would."},"BSB":{"text":"For the flesh craves what is contrary to the Spirit, and the Spirit what is contrary to the flesh. They are opposed to each other, so that you do not do what you want."}},"definableWords":["flesh","Spirit","spirit"],"peopleInVerse":[]},"18":{"text":"But if ye be led of the Spirit, ye are not under the law.","ref":"Galatians 5:18","synthesized":"But if you are led by the Spirit, you are not under the law.","sources":{"KJV":{"text":"But if ye be led of the Spirit, ye are not under the law."},"BSB":{"text":"But if you are led by the Spirit, you are not under the law."}},"definableWords":["Spirit","law"],"peopleInVerse":[]},"19":{"text":"Now the works of the flesh are manifest, which are these; Adultery, fornication, uncleanness, lasciviousness,","ref":"Galatians 5:19","synthesized":"The acts of the flesh are obvious: sexual immorality, impurity, and debauchery;","sources":{"KJV":{"text":"Now the works of the flesh are manifest, which are these; Adultery, fornication, uncleanness, lasciviousness,"},"BSB":{"text":"The acts of the flesh are obvious: sexual immorality, impurity, and debauchery;"}},"definableWords":["flesh"],"peopleInVerse":[]},"20":{"text":"Idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies,","ref":"Galatians 5:20","synthesized":"idolatry and sorcery; hatred, discord, jealousy, and rage; rivalries, divisions, factions,","sources":{"KJV":{"text":"Idolatry, witchcraft, hatred, variance, emulations, wrath, strife, seditions, heresies,"},"BSB":{"text":"idolatry and sorcery; hatred, discord, jealousy, and rage; rivalries, divisions, factions,"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"Envyings, murders, drunkenness, revellings, and such like: of the which I tell you before, as I have also told you in time past, that they which do such things shall not inherit the kingdom of God.","ref":"Galatians 5:21","synthesized":"and envy; drunkenness, orgies, and the like. I warn you, as I did before, that those who practice such things will not inherit the kingdom of God.","sources":{"KJV":{"text":"Envyings, murders, drunkenness, revellings, and such like: of the which I tell you before, as I have also told you in time past, that they which do such things shall not inherit the kingdom of God."},"BSB":{"text":"and envy; drunkenness, orgies, and the like. I warn you, as I did before, that those who practice such things will not inherit the kingdom of God."}},"definableWords":["inherit","kingdom","God"],"peopleInVerse":[]},"22":{"text":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith,","ref":"Galatians 5:22","synthesized":"But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faithfulness,","sources":{"KJV":{"text":"But the fruit of the Spirit is love, joy, peace, longsuffering, gentleness, goodness, faith,"},"BSB":{"text":"But the fruit of the Spirit is love, joy, peace, patience, kindness, goodness, faithfulness,"}},"definableWords":["Spirit","love","joy","peace","patience","kindness"],"peopleInVerse":[]},"23":{"text":"Meekness, temperance: against such there is no law.","ref":"Galatians 5:23","synthesized":"gentleness, and self-control. Against such things there is no law.","sources":{"KJV":{"text":"Meekness, temperance: against such there is no law."},"BSB":{"text":"gentleness, and self-control. Against such things there is no law."}},"definableWords":["law"],"peopleInVerse":[]},"24":{"text":"And they that are Christ’s have crucified the flesh with the affections and lusts.","ref":"Galatians 5:24","synthesized":"Those who belong to Christ Jesus have crucified the flesh with its passions and desires.","sources":{"KJV":{"text":"And they that are Christ’s have crucified the flesh with the affections and lusts."},"BSB":{"text":"Those who belong to Christ Jesus have crucified the flesh with its passions and desires."}},"definableWords":["Christ","flesh"],"peopleInVerse":["Jesus"]},"25":{"text":"If we live in the Spirit, let us also walk in the Spirit.","ref":"Galatians 5:25","synthesized":"Since we live by the Spirit, let us walk in step with the Spirit.","sources":{"KJV":{"text":"If we live in the Spirit, let us also walk in the Spirit."},"BSB":{"text":"Since we live by the Spirit, let us walk in step with the Spirit."}},"definableWords":["live","Spirit","walk","spirit"],"peopleInVerse":[]},"26":{"text":"Let us not be desirous of vain glory, provoking one another, envying one another.","ref":"Galatians 5:26","synthesized":"Let us not become conceited, provoking and envying one another.","sources":{"KJV":{"text":"Let us not be desirous of vain glory, provoking one another, envying one another."},"BSB":{"text":"Let us not become conceited, provoking and envying one another."}},"definableWords":["one"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"BEAR YE ONE ANOTHER'S BURDENS","verses":{"1":{"text":"Brethren, if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted.","ref":"Galatians 6:1","synthesized":"Brothers, if someone is caught in a trespass, you who are spiritual should restore him with a spirit of gentleness. But watch yourself, or you also may be tempted.","sources":{"KJV":{"text":"Brethren, if a man be overtaken in a fault, ye which are spiritual, restore such an one in the spirit of meekness; considering thyself, lest thou also be tempted."},"BSB":{"text":"Brothers, if someone is caught in a trespass, you who are spiritual should restore him with a spirit of gentleness. But watch yourself, or you also may be tempted."}},"definableWords":["spirit","or"],"peopleInVerse":[]},"2":{"text":"Bear ye one another’s burdens, and so fulfil the law of Christ.","ref":"Galatians 6:2","synthesized":"Carry one another’s burdens, and in this way you will fulfill the law of Christ.","sources":{"KJV":{"text":"Bear ye one another’s burdens, and so fulfil the law of Christ."},"BSB":{"text":"Carry one another’s burdens, and in this way you will fulfill the law of Christ."}},"definableWords":["one","way","law","Christ"],"peopleInVerse":[]},"3":{"text":"For if a man think himself to be something, when he is nothing, he deceiveth himself.","ref":"Galatians 6:3","synthesized":"If anyone thinks he is something when he is nothing, he deceives himself.","sources":{"KJV":{"text":"For if a man think himself to be something, when he is nothing, he deceiveth himself."},"BSB":{"text":"If anyone thinks he is something when he is nothing, he deceives himself."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"But let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another.","ref":"Galatians 6:4","synthesized":"Each one should test his own work. Then he will have reason to boast in himself alone, and not in someone else.","sources":{"KJV":{"text":"But let every man prove his own work, and then shall he have rejoicing in himself alone, and not in another."},"BSB":{"text":"Each one should test his own work. Then he will have reason to boast in himself alone, and not in someone else."}},"definableWords":["one","work"],"peopleInVerse":[]},"5":{"text":"For every man shall bear his own burden.","ref":"Galatians 6:5","synthesized":"For each one should carry his own load.","sources":{"KJV":{"text":"For every man shall bear his own burden."},"BSB":{"text":"For each one should carry his own load."}},"definableWords":["one"],"peopleInVerse":[]},"6":{"text":"Let him that is taught in the word communicate unto him that teacheth in all good things.","ref":"Galatians 6:6","synthesized":"Nevertheless, the one who receives instruction in the word must share in all good things with his instructor.","sources":{"KJV":{"text":"Let him that is taught in the word communicate unto him that teacheth in all good things."},"BSB":{"text":"Nevertheless, the one who receives instruction in the word must share in all good things with his instructor."}},"definableWords":["one","word","good"],"peopleInVerse":[]},"7":{"text":"Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap.","ref":"Galatians 6:7","synthesized":"Do not be deceived: God is not to be mocked. Whatever a man sows, he will reap in return.","sources":{"KJV":{"text":"Be not deceived; God is not mocked: for whatsoever a man soweth, that shall he also reap."},"BSB":{"text":"Do not be deceived: God is not to be mocked. Whatever a man sows, he will reap in return."}},"definableWords":["God","man"],"peopleInVerse":[]},"8":{"text":"For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting.","ref":"Galatians 6:8","synthesized":"The one who sows to please his flesh, from the flesh will reap destruction; but the one who sows to please the Spirit, from the Spirit will reap eternal life.","sources":{"KJV":{"text":"For he that soweth to his flesh shall of the flesh reap corruption; but he that soweth to the Spirit shall of the Spirit reap life everlasting."},"BSB":{"text":"The one who sows to please his flesh, from the flesh will reap destruction; but the one who sows to please the Spirit, from the Spirit will reap eternal life."}},"definableWords":["one","flesh","Spirit","spirit","eternal","life"],"peopleInVerse":[]},"9":{"text":"And let us not be weary in well doing: for in due season we shall reap, if we faint not.","ref":"Galatians 6:9","synthesized":"Let us not grow weary in well-doing, for in due time we will reap a harvest if we do not give up.","sources":{"KJV":{"text":"And let us not be weary in well doing: for in due season we shall reap, if we faint not."},"BSB":{"text":"Let us not grow weary in well-doing, for in due time we will reap a harvest if we do not give up."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith.","ref":"Galatians 6:10","synthesized":"Therefore, as we have opportunity, let us do good to everyone, and especially to the family of faith.","sources":{"KJV":{"text":"As we have therefore opportunity, let us do good unto all men, especially unto them who are of the household of faith."},"BSB":{"text":"Therefore, as we have opportunity, let us do good to everyone, and especially to the family of faith."}},"definableWords":["good","family","faith"],"peopleInVerse":[]},"11":{"text":"Ye see how large a letter I have written unto you with mine own hand.","ref":"Galatians 6:11","synthesized":"See what large letters I am using to write to you with my own hand!","sources":{"KJV":{"text":"Ye see how large a letter I have written unto you with mine own hand."},"BSB":{"text":"See what large letters I am using to write to you with my own hand!"}},"definableWords":["see"],"peopleInVerse":[]},"12":{"text":"As many as desire to make a fair shew in the flesh, they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ.","ref":"Galatians 6:12","synthesized":"Those who want to make a good impression outwardly are trying to compel you to be circumcised. They only do this to avoid persecution for the cross of Christ.","sources":{"KJV":{"text":"As many as desire to make a fair shew in the flesh, they constrain you to be circumcised; only lest they should suffer persecution for the cross of Christ."},"BSB":{"text":"Those who want to make a good impression outwardly are trying to compel you to be circumcised. They only do this to avoid persecution for the cross of Christ."}},"definableWords":["make","good","circumcised","Christ"],"peopleInVerse":[]},"13":{"text":"For neither they themselves who are circumcised keep the law; but desire to have you circumcised, that they may glory in your flesh.","ref":"Galatians 6:13","synthesized":"For the circumcised do not even keep the law themselves, yet they want you to be circumcised that they may boast in your flesh.","sources":{"KJV":{"text":"For neither they themselves who are circumcised keep the law; but desire to have you circumcised, that they may glory in your flesh."},"BSB":{"text":"For the circumcised do not even keep the law themselves, yet they want you to be circumcised that they may boast in your flesh."}},"definableWords":["circumcised","keep","law","flesh"],"peopleInVerse":[]},"14":{"text":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world.","ref":"Galatians 6:14","synthesized":"But as for me, may I never boast, except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world.","sources":{"KJV":{"text":"But God forbid that I should glory, save in the cross of our Lord Jesus Christ, by whom the world is crucified unto me, and I unto the world."},"BSB":{"text":"But as for me, may I never boast, except in the cross of our Lord Jesus Christ, through which the world has been crucified to me, and I to the world."}},"definableWords":["Lord","Christ"],"peopleInVerse":["Jesus"]},"15":{"text":"For in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature.","ref":"Galatians 6:15","synthesized":"For neither circumcision nor uncircumcision means anything. What counts is a new creation.","sources":{"KJV":{"text":"For in Christ Jesus neither circumcision availeth any thing, nor uncircumcision, but a new creature."},"BSB":{"text":"For neither circumcision nor uncircumcision means anything. What counts is a new creation."}},"definableWords":["circumcision"],"peopleInVerse":[]},"16":{"text":"And as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God.","ref":"Galatians 6:16","synthesized":"Peace and mercy to all who walk by this rule, even to the Israel of God.","sources":{"KJV":{"text":"And as many as walk according to this rule, peace be on them, and mercy, and upon the Israel of God."},"BSB":{"text":"Peace and mercy to all who walk by this rule, even to the Israel of God."}},"definableWords":["peace","mercy","walk","rule","Israel","God"],"peopleInVerse":[]},"17":{"text":"From henceforth let no man trouble me: for I bear in my body the marks of the Lord Jesus.","ref":"Galatians 6:17","synthesized":"From now on let no one cause me trouble, for I bear on my body the marks of Jesus.","sources":{"KJV":{"text":"From henceforth let no man trouble me: for I bear in my body the marks of the Lord Jesus."},"BSB":{"text":"From now on let no one cause me trouble, for I bear on my body the marks of Jesus."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"18":{"text":"Brethren, the grace of our Lord Jesus Christ be with your spirit. Amen.","ref":"Galatians 6:18","synthesized":"The grace of our Lord Jesus Christ be with your spirit, brothers.  Amen.","sources":{"KJV":{"text":"Brethren, the grace of our Lord Jesus Christ be with your spirit. Amen."},"BSB":{"text":"The grace of our Lord Jesus Christ be with your spirit, brothers.  Amen."}},"definableWords":["grace","Lord","Christ","spirit"],"peopleInVerse":["Jesus"]}}}};